export function getChapterQuiz(chapterId: string): QuizQuestion[] {
  return quizQuestions.filter(q => q.chapterId === chapterId);
}

export function getMasterTestQuestions(): QuizQuestion[] {
  return masterTestQuestionIds
    .map(id => quizQuestions.find(q => q.id === id))
    .filter((q): q is QuizQuestion => q !== undefined);
}